Analyze the following OpenMP code for potential race conditions. Identify all issues and suggest fixes using appropriate data-sharing attributes:

int sum = 0;
int arr[1000];
// Initialize arr with values 1 to 1000
for(int i=0; i<1000; i++) arr[i] = i+1;

#pragma omp parallel num_threads(4)
{
    int tid = omp_get_thread_num();
    for(int i=tid*250; i<(tid+1)*250; i++) {
        sum += arr[i];
        arr[i] = arr[i] * 2;
    }
}
printf("Sum = %d\n", sum);

Given a parallel matrix multiplication algorithm where each thread computes a portion of the result matrix, explain how variable scope choices affect correctness and performance. Design appropriate data-sharing attributes for all variables in the code snippet below:

#define N 1000
double A[N][N], B[N][N], C[N][N];

void matmul() {
    int i, j, k;
    double temp;

    #pragma omp parallel for private(i,j,k,temp)
    for (i = 0; i < N; i++) {
        for (j = 0; j < N; j++) {
            temp = 0.0;
            for (k = 0; k < N; k++) {
                temp += A[i][k] * B[k][j];
            }
            C[i][j] = temp;
        }
    }
}
